import os
import random
import math
import torch
import torchaudio
import torchaudio.functional as AF
import numpy as np
from torch.utils.data import Dataset

def load_protocol(path):
    items = []
    with open(path) as f:
        for line in f:
            parts = line.strip().split()
            if len(parts) < 5:
                continue
            utt_id = parts[1]
            label = 1 if parts[4] == 'bonafide' else 0
            items.append((utt_id, label))
    return items

def load_audio(path, target_sr=16000):
    wav, sr = torchaudio.load(path)
    if wav.shape[0] > 1:
        wav = wav.mean(0, keepdim=True)
    if sr != target_sr:
        wav = torchaudio.functional.resample(wav, sr, target_sr)
    return wav.squeeze(0)

def mu_law_codec(wav, mu=255):
    enc = AF.mu_law_encoding(wav, mu + 1)
    dec = AF.mu_law_decoding(enc, mu + 1)
    return dec

def a_law_codec(wav):
    A = 87.6
    sign = torch.sign(wav)
    absw = torch.clamp(torch.abs(wav), max=1.0)
    logA = math.log(A)
    mask = absw < (1.0 / A)
    y = torch.where(mask,
                    A * absw / (1 + logA),
                    (1 + torch.log(absw.clamp(min=1e-6) * A)) / (1 + logA))
    y = sign * y
    y = torch.round(y * 127) / 127
    absy = torch.abs(y)
    sign2 = torch.sign(y)
    mask2 = absy < (1.0 / (1 + logA))
    x = torch.where(mask2,
                    absy * (1 + logA) / A,
                    torch.exp(absy * (1 + logA) - 1) / A)
    return sign2 * x

def narrowband_filter(wav, sr=16000, low=300, high=3400):
    wav = AF.highpass_biquad(wav, sr, low)
    wav = AF.lowpass_biquad(wav, sr, high)
    return wav

def downsample_codec(wav, sr=16000, target_sr=8000):
    w = AF.resample(wav.unsqueeze(0), sr, target_sr)
    w = AF.resample(w, target_sr, sr).squeeze(0)
    return w

def linear_conv_noise(wav):
    n_taps = random.choice([5, 9, 17])
    h = torch.randn(n_taps) * 0.1
    h[n_taps // 2] += 1.0
    h = h / h.abs().sum()
    wav_p = torch.nn.functional.pad(wav.unsqueeze(0).unsqueeze(0), (n_taps // 2, n_taps // 2))
    out = torch.nn.functional.conv1d(wav_p, h.view(1, 1, -1)).squeeze()
    return out

def impulsive_noise(wav):
    n = wav.shape[0]
    num = max(1, n // 4000)
    idx = torch.randint(0, n, (num,))
    amp = torch.randn(num) * 0.1
    wav = wav.clone()
    wav[idx] = wav[idx] + amp
    return wav

def stationary_noise(wav, snr_db_range=(8, 40)):
    snr_db = random.uniform(*snr_db_range)
    sig_p = wav.pow(2).mean().clamp(min=1e-10)
    snr = 10 ** (snr_db / 10)
    noise_p = sig_p / snr
    noise = torch.randn_like(wav) * noise_p.sqrt()
    return wav + noise

def colored_noise(wav, snr_db_range=(10, 30)):
    # pink-ish noise via lowpass white
    snr_db = random.uniform(*snr_db_range)
    sig_p = wav.pow(2).mean().clamp(min=1e-10)
    snr = 10 ** (snr_db / 10)
    noise_p = sig_p / snr
    noise = torch.randn_like(wav)
    noise = AF.lowpass_biquad(noise, 16000, random.uniform(500, 4000))
    noise = noise * (noise_p.sqrt() / noise.std().clamp(min=1e-6))
    return wav + noise

# Try real codec encoding via torchaudio
_HAS_EFFECTOR = False
try:
    from torchaudio.io import AudioEffector
    _HAS_EFFECTOR = True
except Exception:
    pass

def real_codec_aug(wav, sr=16000):
    if not _HAS_EFFECTOR:
        return wav
    try:
        codec = random.choice(['mp3', 'vorbis', 'wav_alaw', 'wav_ulaw'])
        if codec == 'mp3':
            effector = AudioEffector(format='mp3', encoder='libmp3lame')
        elif codec == 'vorbis':
            effector = AudioEffector(format='ogg', encoder='vorbis')
        elif codec == 'wav_alaw':
            effector = AudioEffector(format='wav', encoder='pcm_alaw')
        else:
            effector = AudioEffector(format='wav', encoder='pcm_mulaw')
        x = wav.unsqueeze(-1)  # (T, 1)
        y = effector.apply(x, sr)
        y = y.squeeze(-1)
        # match length
        if y.shape[0] >= wav.shape[0]:
            y = y[:wav.shape[0]]
        else:
            y = torch.nn.functional.pad(y, (0, wav.shape[0] - y.shape[0]))
        return y
    except Exception:
        return wav

def apply_codec_aug(wav):
    choice = random.random()
    if choice < 0.15:
        wav = mu_law_codec(wav)
    elif choice < 0.25:
        try:
            wav = a_law_codec(wav)
        except Exception:
            wav = mu_law_codec(wav)
    elif choice < 0.40:
        wav = downsample_codec(wav, target_sr=8000)
        wav = narrowband_filter(wav)
        if random.random() < 0.5:
            wav = mu_law_codec(wav)
    elif choice < 0.50:
        wav = downsample_codec(wav, target_sr=8000)
    elif choice < 0.60:
        wav = downsample_codec(wav, target_sr=12000)
    elif choice < 0.75:
        wav = real_codec_aug(wav)
    elif choice < 0.82:
        wav = AF.highpass_biquad(wav, 16000, random.uniform(100, 400))
    return wav

class SpoofDataset(Dataset):
    def __init__(self, items, flac_dir, max_sec=4.0, train=True, augment=False):
        self.items = items
        self.flac_dir = flac_dir
        self.max_len = int(max_sec * 16000)
        self.train = train
        self.augment = augment

    def __len__(self):
        return len(self.items)

    def _augment(self, wav):
        if random.random() < 0.4:
            try:
                wav = linear_conv_noise(wav)
            except Exception:
                pass
        if random.random() < 0.85:
            try:
                wav = apply_codec_aug(wav)
            except Exception:
                pass
        if random.random() < 0.4:
            wav = stationary_noise(wav)
        if random.random() < 0.25:
            wav = colored_noise(wav)
        if random.random() < 0.15:
            wav = impulsive_noise(wav)
        if random.random() < 0.5:
            gain = random.uniform(0.5, 1.4)
            wav = wav * gain
        wav = torch.clamp(wav, -1.0, 1.0)
        return wav

    def __getitem__(self, idx):
        utt_id, label = self.items[idx]
        path = os.path.join(self.flac_dir, utt_id + '.flac')
        wav = load_audio(path)
        if self.train:
            if wav.shape[0] >= self.max_len:
                start = random.randint(0, wav.shape[0] - self.max_len)
                wav = wav[start:start + self.max_len]
            else:
                # repeat
                reps = self.max_len // wav.shape[0] + 1
                wav = wav.repeat(reps)[:self.max_len]
        else:
            if wav.shape[0] > self.max_len:
                # center crop
                start = (wav.shape[0] - self.max_len) // 2
                wav = wav[start:start + self.max_len]
            else:
                reps = self.max_len // wav.shape[0] + 1
                wav = wav.repeat(reps)[:self.max_len]
        if self.augment:
            wav = self._augment(wav)
        return wav, label, utt_id

def collate(batch):
    wavs = torch.stack([b[0] for b in batch])
    labels = torch.tensor([b[1] for b in batch], dtype=torch.long)
    ids = [b[2] for b in batch]
    return wavs, labels, ids
